args.sparql:
SELECT ?athlete ?label WHERE {
  wd:Q1810896 wdt:P527 ?competition .
  ?competition wdt:P641 wd:Q239890 ;
              wdt:P5142 wd:Q76833059 ;
              wdt:P1346 ?athlete .
  ?athlete rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}

SELECT ?athlete ?label WHERE {
  ?wcCompetition wdt:P361 wd:Q1810896 ;
                wdt:P641 wd:Q239890 ;
                wdt:P5142 wd:Q76833059 ;
                wdt:P512 ?athlete .

  ?ecEvent wdt:P361 wd:Q1467563 ;
           wdt:P641 wd:Q239890 ;
           wdt:P5142 wd:Q76833059 ;
           wdt:P1346 ?athlete ;
           (wdt:P585|wdt:P580) ?date .
  FILTER(?date >= "1977-01-01T00:00:00Z"^^xsd:dateTime &&
         ?date <= "1986-12-31T23:59:59Z"^^xsd:dateTime)

  ?athlete rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}
GROUP BY ?athlete ?label
HAVING(COUNT(DISTINCT ?ecEvent) >= 5)
